/**
 * Closes the CPIO output stream as well as the stream being filtered.
 * 
 * @throws IOException
 *             if an I/O error has occurred or if a CPIO file error has
 *             occurred
 */

public void close() throws IOException {
    if (!this.closed) {
        this.finish();
        out.close();
        this.closed = true;
    }
}

